  (15773, '11303357', 'BEST FINE (HONG KONG) LIMITED', 'Household & Personal Products', '990330802', 'Best Fine (Hong Kong) Limited', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'Antonio Rendina', '1599218', 'Physical RT: To follow up on specific mitigants taken by company to reduce, manage or adapt to physical risks in the context of both direct business operations and the company''s value/supply chain.', NULL, NULL, NULL, 'HONG KONG', NULL, NULL, 'Peter Jared Delaney', '1665885', 'HK', 'CRQ v2', NULL, NULL, NULL, NULL, '1729785600', NULL, NULL, '2022-11-10 01:38:42', '2023-09-05 01:42:31'),
  (17979, '13553468', 'LNAME13553468', 'T & S - Aviation', '990058214', 'TURKISH AIRLINES', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Recommended additional analysis to understand the new & future fleet mix plans, given the recent order for MAX aircraft and understand if there are any future additional costs related to such orders. The parent entity is predicted to default in even in an orderly climate transition scenario, which does not take into account large expenditures, such as the purchase of new aircraft. This should be built into the Financial Risk Trigger projections required.', NULL, 'Liu, Shuk Fan', '1551380', 'JAPAN', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'JP', 'CRQ v2', NULL, NULL, NULL, NULL, '1726012800', NULL, NULL, '2023-03-21 13:31:31', '2023-07-25 06:45:57'),
  (18302, '12269926', 'CHINA ZHENHUA OIL CO . , LTD.', 'Commodity Traders', '990065210', 'CHINA ZHENHUA OIL CO., LTD', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'CA to raise Physical RT: to follow up on specific mitigants taken by company to reduce, manage or adapt to physical risks in the context of both direct business operations and the company''s value/supply chain.', NULL, NULL, NULL, 'CHINA', 'Existing to Bank', NULL, 'null null', '2006082', 'CN', 'CRQ v2', NULL, NULL, NULL, NULL, '1729180800', NULL, NULL, '2023-05-15 19:09:11', '2023-09-12 10:13:00'),
