  (18686, '11281015', 'PAPUA NEW GUINEA LIQUEFIED NATURAL GAS GLOBAL COMPANY LDC', 'O&G Producer', '990000355', 'EXXONMOBIL CORPORATION', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, NULL, NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'US', 'CRQ v2', NULL, NULL, NULL, NULL, '1729785600', NULL, NULL, '2023-05-19 07:42:53', '2023-07-13 07:53:11'),
  (18707, '13760113', 'Hanwha Energy USA Holdings Corporation', 'Utilities', '990053627', 'HANWHA', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'If information is available, to report in the BCA P2 the Client-level target for solar power increase vs current solar power generation operational and assess the financial needs required to meet the targets and whether the Client has adequate liquidity pools to reach its own targets', NULL, NULL, NULL, 'KOREA, REPUBLIC OF', 'Existing to Bank', NULL, 'Ewa Baran', '1663704', 'KR', 'CRQ v2', NULL, NULL, NULL, NULL, '1729267200', NULL, NULL, '2023-05-19 08:00:41', '2023-08-04 15:08:42'),
  (18737, '11062847', 'AMBUJA CEMENTS LIMITED', 'Building Products, Construction & Engineering', '990278632', 'LAFARGEHOLCIM', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', 'Proposed analysis to understand the future fuel mix / clinker materials (to better understand the clinker ratio) that will be used in cement production and also understand the security of these additional materials (slag, fly ash, etc..) production given that they are byproducts of high carbon activities, such as burning of coal, assuming that these will become more scarce as other sector decarbonization efforts continue.', NULL, NULL, NULL, 'SWITZERLAND', 'Existing to Bank', NULL, 'null null', '2003706', 'CH', 'CRQ v2', NULL, NULL, NULL, NULL, '1725379200', NULL, NULL, '2023-05-19 08:52:30', '2023-07-26 15:07:50'),
  (18773, NULL, NULL, NULL, NULL, NULL, 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'Piyush Mundra', '1191828', 'The client''s green brag is driven by good scores from the PD model despite no data on governance and disclosures. Hence would recommend a RT to reach out to the client to know more about its climate transition plans', NULL, NULL, NULL, NULL, 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', NULL, 'CRQ v2', NULL, NULL, NULL, NULL, '1729180800', NULL, NULL, '2023-05-19 11:09:49', '2023-08-30 10:29:28'),
  (19407, '13960873', 'FORAN ENERGY GROUP CO.,LTD.', 'Utilities', '990375700', 'Foran Energy Group Co., Ltd.', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', NULL, NULL, 'To follow up on specific mitigants taken by company to reduce, manage or adapt to physical risks in the context of both direct business operations and the company''s value/supply chain.', NULL, NULL, NULL, 'CHINA', 'New to Bank', NULL, 'null null', '2006082', 'CN', 'CRQ v2', NULL, NULL, NULL, NULL, '1729180800', NULL, NULL, '2023-07-03 06:20:41', '2023-07-24 06:18:33'),
  (19415, '13962268', 'NEWGEN POWER KWINANA PTY LTD', 'Utilities', '990000465', 'SUMITOMO CORPORATION GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'Shuk Fan Liu', '1551380', 'For accurate physical risk assessment, please provide full address of power station or key operating asset if not already provided in BCA Part 2.', NULL, NULL, NULL, 'AUSTRALIA', 'New to Bank', NULL, 'Shubham Harsh', '2008896', 'AU', 'CRQ v2', NULL, NULL, NULL, NULL, '1729785600', NULL, NULL, '2023-07-06 02:10:55', '2023-07-21 03:11:31'),
  (19422, '11047686', 'BOC AVIATION LIMITED', 'Financial Institutions', '990003964', 'BANK OF CHINA', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'Antonio Rendina', '1599218', 'To estimate in the BCA P2 the required financial needs to increase the % of newer technology fleet aircrafts to 75% at the end of 2025, vs YE22 level of 71%, and assess whether the Client disposes of adequate liquidity pool to reach its target.', NULL, NULL, NULL, 'SINGAPORE', 'New to Bank', NULL, 'V Kavya Gowri', '2006519', 'SG', 'CRQ v2', NULL, NULL, NULL, NULL, '1729785600', NULL, NULL, '2023-07-07 08:52:10', '2023-07-25 02:31:52'),
  (19581, '11156069', 'BGP Inc., China National Petroleum Corporation', 'O&G Producer', '990027478', 'CHINA NATIONAL PETROLEUM CORPORATION (CNPC)', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', 'Additional analysis to understand the emissions production from pipeline / storage services and if these are material compared to O&G production as well as whether Scope 1, 2 or 3 is the most impactful.', NULL, NULL, NULL, 'CHINA', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'CN', 'CRQ v2', NULL, NULL, NULL, NULL, '1729814400', NULL, NULL, '2023-07-18 12:56:42', '2023-11-29 02:16:41'),
  (19685, '13714413', 'XIN FENG MING GROUP HUZHOU ZHONGSHI TECHNOLOGY CO., LTD', 'Other Materials', '990333735', 'XIN FENG MING GROUP CO., LTD.', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'Same physical RT from previous CRA retained; transition RT from previous CRA no longer applicable: To inquire about quantifiable emissions targets (Scope 1, 2 and 3 emissions) and an overall plan to respond to future emissions related policies, environmental laws and regulation.', NULL, NULL, NULL, 'CHINA', 'Existing to Bank', NULL, 'null null', '2006082', 'CN', 'CRQ v2', NULL, NULL, NULL, NULL, '1728921600', NULL, NULL, '2023-07-19 08:03:48', '2023-11-21 10:57:59'),
  (19816, '13606646', 'SHINAS GENERATING COMPANY SAOC', 'Utilities', '990000084', 'MITSUI GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'In the BCA P2 to highlight the transmission channels through which higher levels of heat could impact the plant efficiency, and ultimately impact the Client''s revenue generation', NULL, NULL, NULL, 'JAPAN', 'Existing to Bank', NULL, 'Ewa Baran', '1663704', 'JP', 'CRQ v2', NULL, NULL, NULL, NULL, '1726790400', NULL, NULL, '2023-07-20 08:52:09', '2023-11-27 05:25:49'),
  (19832, '13902171', 'Coleman Logistics Assets LLC', 'CRE', '990028935', 'MAPLETREE INVESTMENT PTE LTD', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Business to check with the client if operational emissions of the entire building portfolio are included in Scope1/2. Since majority of assets are leased, if these are only included in Scope 3, then company is expected to disclose Scope 3 emissions as well as this is the most material component.', NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Klaudia Muszynska', '2001097', 'US', 'CRQ v2', NULL, NULL, NULL, NULL, '1728921600', NULL, NULL, '2023-07-20 09:39:31', '2023-12-05 15:54:26'),
  (19918, '13079648', 'NOVELIS INC', 'Metal & Mining Producers', '990000281', 'ADITYA BIRLA GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Additional analysis recommended to understand the energy utilistaion mix of the client for its recycling and produciton processes, based on the geography grid intensity. (e.g. is electricity grid used made of X% O&G and Y% Renewable etc..)', NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'US', 'CRQ v2', NULL, NULL, NULL, NULL, '1725897600', NULL, NULL, '2023-07-20 12:17:16', '2023-11-28 15:40:40'),
