  (20163, '13803774', 'SINOPEC CENTURY BRIGHT CAPITAL INVESTMENT (UK) LIMITED', 'O&G Refiners and Petrochemicals', '990045320', 'SINOPEC', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Business to comment on the energy efficiency of refineries within the Group. Does the group monitor this or have plans to improve this ? Example - Via ''Best Technology'' index or any other equivalent intensity index used in the industry to gauge efficiency of a refinery.', NULL, NULL, NULL, 'UNITED KINGDOM', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'GB', 'CRQ v2', NULL, NULL, NULL, NULL, '1725897600', NULL, NULL, '2023-07-20 17:26:13', '2023-11-14 13:58:29'),
  (20193, '13798339', 'L NAME 13798339', 'CRE', '990000257', 'KEPPEL CORPORATION GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Group mentions investments towards having a Green mark certification for certain assets. Business to confirm whether the asset under consideration will also certified by Green Mark, if not, how does the group decide which propertis are to be certified if the policy is not Group wide.', NULL, NULL, NULL, 'SINGAPORE', 'Existing to Bank', NULL, 'Shubham Harsh', '2008896', 'SG', 'CRQ v2', NULL, NULL, NULL, NULL, '1726012800', NULL, NULL, '2023-07-20 18:03:43', '2023-11-07 00:17:58'),
  (20313, '11273243', 'SHINSEGAE ENGINEERING AND CONSTRUCTION INC', 'Building Products, Construction & Engineering', '990060142', 'SHINSEGAE', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Antonio Rendina', '1599218', 'In the BCA P2, to comment on the level of energy efficiency of the properties being constructed', NULL, NULL, NULL, 'KOREA, REPUBLIC OF', 'Existing to Bank', NULL, 'Peter Jared Delaney', '1665885', NULL, 'CRQ v2', NULL, NULL, NULL, NULL, '1726790400', NULL, NULL, '2023-07-24 13:15:55', '2023-12-04 01:17:37'),
  (20432, '13964525', 'SNC BOTANIQUE', 'Transportation and Storage', '990052771', 'DUBAI WORLD', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'Chirag Jain', '1575987', 'As part of the integration of Climate Risk into the BCA P2, the Credit Analyst is encouraged to assess the Impact of extension of EU-ETS (from Jan''24) on the entity.', NULL, NULL, NULL, 'FRANCE', 'New to Bank', NULL, 'Monalisa Banerjee', '1563645', 'SG', 'CRQ v2', NULL, NULL, NULL, NULL, '1729785600', NULL, NULL, '2023-08-03 10:29:57', '2023-08-23 12:53:46'),
  (20549, '13966161', 'CLEAN INDUSTRIAL REITS CO LTD', 'CRE', '990000413', 'SK GROUP', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'To highlight whether how climate regulations on the real estate sector in South Korea might lead to a potential financial risks for the company', NULL, 'Rendina, Antonio', '1599218', 'KOREA, REPUBLIC OF', 'New to Bank', NULL, 'Shubham Harsh', '2008896', 'KR', 'CRQ v2', NULL, NULL, NULL, NULL, '1729296000', NULL, NULL, '2023-09-14 09:19:14', '2023-11-28 17:08:15'),
  (20630, '13921367', 'SEA 264 LEASING CO. LIMITED', 'O&G Tanker - Water Transport', '990048404', 'CHINA MERCHANTS BANK', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Ashish Sharma1', '1493405', 'To comment on whether the underlying vessel serves EU ports and has a gross tonnage above 5,000. This this holds true, the Client will impacted by the EU ETS, as a result of which the Credit Analyst is requested to assess the financial impact of it and estimate the additional cost for compliance', NULL, NULL, NULL, 'HONG KONG', 'Existing to Bank', NULL, 'null null', '1618369', 'HK', 'CRQ v2', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-10-09 13:29:45', '2024-01-03 09:01:10'),
  (20633, '13885710', 'PT Qmb New Energy Materials', 'Metal & Mining Producers', '990369654', 'GEM CO., LTD', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'Elliott Rouse', '1489063', 'Recommendation to gather operation plant locations for physical risk assessment, as well as understand the trade-off in Scope 1 emissions for Scope 3 emissions savings due to green end product in the wider value chain.', NULL, NULL, NULL, 'INDONESIA', 'Existing to Bank', NULL, 'Shubham Harsh', '2008896', 'ID', 'CRQ v2', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-10-10 08:14:41', '2024-02-25 02:16:43'),
  (20669, '13806727', 'HWIGYEONG 3RD DISTRICT HOUSING REDEVELOPMENT CONSORTIUM', 'CRE', '990346477', 'HWIGYEONG 3RD DISTRICT HOUSING REDEVELOPMENT CONSORTIUM', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Harshvardhan V', '1493184', 'Please capture detailf of property insurance in the BCA and whether climate related risks are covered ? (damage costs mainly) -- In section 3, this is marked as no insurance due to non availability of data', NULL, NULL, NULL, 'KOREA, REPUBLIC OF', 'Existing to Bank', NULL, 'Peter Jared Delaney', '1665885', 'KR', 'CRQ v2', NULL, NULL, NULL, NULL, '1729785600', NULL, NULL, '2023-10-15 18:09:57', '2023-12-21 07:01:48'),
  (21011, '13963575', 'PROJECT SABLE', 'Utilities', '990010689', 'ENGIE', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'CA is request to elaborate physical risk adaptation measures undertaken for the specific project in BCA part II', NULL, NULL, NULL, 'SAUDI ARABIA', 'New to Bank', NULL, 'Ajith Kumar', '1286637', 'GB', 'CRQ v2', NULL, NULL, NULL, NULL, '1729814400', NULL, NULL, '2023-10-20 11:33:08', '2023-12-16 15:33:24'),
  (21027, '13744676', 'TBC-Ball Beverage Can Holdings Limited', 'Other Materials', '990044736', 'T.C.C.GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Physical Risk Trigger: To follow up on (1) the potential impact of physical risks and (2) company''s plan to reduce, manage or adapt to physical risks in the context of both direct business operations and the company''s value/supply chain.', NULL, NULL, NULL, 'HONG KONG', 'New to Bank', NULL, 'Peter Jared Delaney', '1665885', 'HK', 'CRQ v2', NULL, NULL, NULL, NULL, '1729296000', NULL, NULL, '2023-10-25 09:57:36', '2023-12-05 03:00:45'),
  (21036, '13952865', 'TCI TEXARKANA INC.', 'Metal & Mining Producers', '990048012', 'TA CHEN STAINLESS GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'Elliott Rouse', '1489063', 'To understand the underlying process of the client for casting and rolling - and what is the energy mix used to heat material for the operations (coal, gas, renewables etc..)', NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'New to Bank', NULL, 'Ajith Kumar', '1286637', 'US', 'CRQ v2', NULL, NULL, NULL, NULL, '1725897600', NULL, NULL, '2023-10-27 14:46:45', '2023-12-12 17:17:21'),
  (21095, '13953091', 'J.C.B SERVICE', 'Other Capital Goods', '990011217', 'JC BAMFORD', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'Elliott Rouse', '1489063', 'Recommended additional analysis to seek out reports to see if demand for JCB products could be affected in the long-run by climate change. For example, does earthmoving / agricultural facing products see a larger potential impact and then have JCB made allowances for such differences in potential demand changes.', NULL, NULL, NULL, 'UNITED KINGDOM', 'New to Bank', NULL, 'V Kavya Gowri', '2006519', 'GB', 'CRQ v2', NULL, NULL, NULL, NULL, '1729296000', NULL, NULL, '2023-11-09 10:00:04', '2023-12-08 13:06:51'),
  (21114, '13761664', 'LNAME13761664', 'T & S - Aviation', '990060274', 'GOVERNMENT OF QATAR GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Analyse potential additional costs from any ETS / Carbon Policies coming into affect. What could the potential emissions looks like in the next 5 years and cost of purchasing permits / credits to adhere to it. Additionally analyse what potential cost of retrofitting / upgrading current aviation equipment as a transition measure to reduce emissions. Evaluate how persistently higher temperatures, may alter demand for air travel to certain locations, which may increase or decrease revenue streams. Probe whether rising temperatures will necessitate a reduction in payload (passengers or cargo). Sensitise financials for potential costs from operational impacts such as delayed or cancelled flights.', NULL, NULL, NULL, 'CAYMAN ISLANDS', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'QA', 'CRQ v3', NULL, NULL, NULL, NULL, '1729180800', NULL, NULL, '2023-11-18 06:40:23', '2024-07-11 06:21:50'),
