  (21200, '13919322', 'GEM HONG KONG INTERNATIONAL CO., LIMITED', 'Metal & Mining Producers', '990369654', 'GEM CO., LTD', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, NULL, NULL, NULL, NULL, 'HONG KONG', 'Existing to Bank', NULL, 'Ajith Kumar', '1286637', 'HK', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-11-30 06:51:32', '2024-02-07 10:37:20'),
  (21213, '13625404', 'LNAME13625404', 'T & S - Container Water Transport', '990320631', 'CHINA COSCO SHIPPING CORPORATION LIMITED', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'In line with the technical approach under MARPOL for reduction of carbon intensity by at least 40% by 2030, by when would the EEXI / EEDI rating for the fleet be completed and what is the action plan for vessels where the attained EEXI /EEDI is less than equal to the required EEXI.', NULL, NULL, NULL, 'JAPAN', 'Existing to Bank', NULL, 'Peter Jared Delaney', '1665885', 'JP', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-04 12:32:02', '2024-02-26 01:29:24'),
  (21221, '13631100', 'LNAME13631100', 'T & S - Bulker Water Transport', '990320631', 'CHINA COSCO SHIPPING CORPORATION LIMITED', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Since CII is rated E, regulatory requirements are to submit a corrective action plan on how client plans to achieve rating C or better. Please share an udpate on what the corrective action plan is.', NULL, NULL, NULL, 'JAPAN', 'Existing to Bank', NULL, 'Peter Jared Delaney', '1665885', 'JP', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-05 09:58:22', '2024-02-26 01:39:41'),
  (21241, '11211050', 'POSCO-THAINOX PUBLIC COMPANY LIMITED', 'Metal & Mining Producers', '990035917', 'POSCO HOLDINGS', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'Elliott Rouse', '1489063', 'Recommend analysis to see if POSCO group reports and climate management practices can be applied down onto the legal entity - currently little disclosure in the companies own report, however this could be improved if they are covered by group level climate management.', NULL, NULL, NULL, 'THAILAND', 'Existing to Bank', NULL, 'Devika Rose Roy', '2001769', 'TH', 'CRQ v3', NULL, NULL, NULL, NULL, '1729296000', NULL, NULL, '2023-12-08 15:14:56', '2023-12-26 04:17:07'),
  (21256, '11147646', 'APPLE INC', 'Technology Hardware & Equipment', '990036152', 'APPLE INC GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'As per mail from CA:Apple does not disclose intermediate emission targets but a long-term goal. That is “to be carbon neutral across its entire value chain by 2030. Apple’s plan centres on an aggressive 75 percent reduction in overall carbon emissions from 2015 levels”. Based on the Environmental Progress Report, page 12, 2015 goss emissions were $38.4 million metric tons CO2e; so, by 2030 Apple plans to cut gross emissions to 9.6 million metric tons CO2e.Because ~98% of the gross emission are Scope 3 generated from product life cycle (see page 77 of the Environmental Report); we can infer that most plans are geared towards reducing Scope 3 emissions in the coming years.', NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Ajith Kumar', '1286637', 'US', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-11 14:29:21', '2024-01-31 23:28:35'),
  (21258, '13784138', 'APPLE OPERATIONS EUROPE LIMITED', 'Technology Hardware & Equipment', '990036152', 'APPLE INC GROUP', 'Descoped', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Chirag Jain', '1575987', 'As per mail from CA:Apple does not disclose intermediate emission targets but a long-term goal. That is “to be carbon neutral across its entire value chain by 2030. Apple’s plan centres on an aggressive 75 percent reduction in overall carbon emissions from 2015 levels”. Based on the Environmental Progress Report, page 12, 2015 goss emissions were $38.4 million metric tons CO2e; so, by 2030 Apple plans to cut gross emissions to 9.6 million metric tons CO2e.Because ~98% of the gross emission are Scope 3 generated from product life cycle (see page 77 of the Environmental Report); we can infer that most plans are geared towards reducing Scope 3 emissions in the coming years.', NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Ajith Kumar', '1286637', 'US', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2023-12-11 14:31:05', '2024-04-04 11:50:37'),
  (21269, '11123690', 'RATCH GROUP PUBLIC COMPANY LIMITED', 'Utilities', '990171651', 'RATCHABURI ELECTRICITY GENERATING HOLDING PCL', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Antonio Rendina', '1599218', 'To add Climate Risk Analysis highlighted high carbon pricing risk as per email sent by Climate Advisor Team on 13/14 Feb 2024', NULL, NULL, NULL, 'THAILAND', 'Existing to Bank', NULL, 'Ajith Kumar', '1286637', 'TH', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-11 15:01:30', '2024-02-20 07:15:02'),
  (21345, '13692902', 'RYANAIR DESIGNATED ACTIVITY COMPANY', 'T & S - Aviation', '990336704', 'Ryanair Holdings Plc', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', 'Understanding of the costs associated with SAF commitment - where will this be sourced from and at what cost to the entity. Has efficient pricing method been implemented to follow regional SAF commitments and regulations?', NULL, 'Liu, Shuk Fan', '1551380', 'IRELAND', 'Existing to Bank', NULL, 'Shubham Harsh', '2008896', 'IE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-12 08:28:15', '2024-03-05 07:59:30'),
  (21355, '11019549', 'C.F.L. ENTERPRISE LIMITED', 'Consumer Durables & Apparel', '990002137', 'C.F.L', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, NULL, NULL, NULL, NULL, 'HONG KONG', 'Existing to Bank', NULL, 'Gowtham  Radhakrishnan', '1668331', 'HK', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-12 08:39:54', '2024-03-13 03:47:38'),
  (21358, '13756760', 'LS AUTOMOTIVE MEXICO S.A. DE C.V.', 'Automobiles & Components', '990032279', 'LS GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'To comment on the Client''s revenue breakdown by product type and highlight the revenue flow more exposed to risks to the EV transition', NULL, NULL, NULL, 'KOREA, REPUBLIC OF', 'Existing to Bank', NULL, 'Yvonne  Jen', '1600990', 'KR', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-12 08:44:13', '2024-03-14 19:05:26'),
  (21361, '13752301', 'ADANI ELECTRICITY MUMBAI LIMITED', 'Utilities', '990023603', 'ADANI GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'The Client has estimated potential a financial impact up to 385 million INR following a 30days shot down due to acute physical events. Credit Analyst is requested to add this information into the BCA P2, assess the materiality of it and compare it to the Client''s reported EBIDTA', NULL, NULL, NULL, 'INDIA', 'Existing to Bank', NULL, 'Yvonne  Jen', '1600990', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-12 08:44:57', '2024-01-26 07:24:32'),
  (21398, '11111080', 'SAN MIGUEL CORPORATION', 'O&G Refiners and Petrochemicals', '990035844', 'SAN MIGUEL GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', '1. Philipines country concentration - a country which is exposed to very high climate risk. PLease check with the client for location of key operating assets across the main businesses (Petron refineries, F&B industry factories etc), so we are able to quantify the physical risk impact on the company ---> Are all these assets protected against damage/disruption risk from cliamte events via insurance. Please comment on these aspects in the BCA2. Can RM check with the client and share a quantified coal power plan for the medium term (2-5 years) -> with forward looking adherence both on power capacity and generation.  Also how much is the current revenue dependency on thermal coal ? 59% is the share of generational capacity but what about the share in terms of actual generation/utlisiation Comment on client strategy and these data points in the BCA.', NULL, NULL, NULL, 'PHILIPPINES', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'PH', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-12 09:03:30', '2024-02-02 08:10:11'),
  (21404, '11153184', 'CUS UPSSH HNANPSB', 'Metal & Mining Producers', '990026172', 'SAJJAN JINDAL GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', '-	Potential P&L impact from additional operating expenses arising from purchase of ESCerts to comply with firm target reductions. Worth incorporating some analysis into what JSW’s target is and what is the gap that needs to be filled with certificates and at what cost. Follow up to understand if this is intended to materially change, given their commitment to ramp up future production. The company has formulated an internal carbon shadow pricing of USD 20/tonne to make itself future ready related to emerging regulations on carbon.-	Imposition of a carbon tax on imported products under the EU CBAM will also have financial implications in terms of reduced profit margins of products exported to Europe, hence analysis on volume of European product flow should be assessed.-	Potential P&L impacts arising from (i) CAPEX spends on additional new low carbon technology to improve energy efficiency and CCU capabilities as well as (ii) reduced dema', NULL, NULL, NULL, 'INDIA', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-12 09:17:56', '2024-03-14 05:10:25'),
  (21409, '13915843', 'JINDAL STEEL ODISHA LIMITED', 'Metal & Mining Producers', '990030793', 'NAVEEN JINDAL GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', '-	Potential P&L impact from additional operating expenses arising from purchase of ESCerts to comply with firm target reductions. Worth incorporating some analysis into what JSW’s target is and what is the gap that needs to be filled with certificates and at what cost. Follow up to understand if this is intended to materially change, given their commitment to ramp up future production. The company has formulated an internal carbon shadow pricing of USD 20/tonne to make itself future ready related to emerging regulations on carbon.-	Imposition of a carbon tax on imported products under the EU CBAM will also have financial implications in terms of reduced profit margins of products exported to Europe, hence analysis on volume of European product flow should be assessed.-	Potential P&L impacts arising from (i) CAPEX spends on additional new low carbon technology to improve energy efficiency and CCU capabilities as well as (ii) reduced dema', NULL, NULL, NULL, 'INDIA', 'Existing to Bank', NULL, 'Renjith  Scariah', '1540001', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-12 09:21:11', '2024-01-30 06:12:19'),
  (21450, '11228457', 'VITOL UPSTREAM GHANA LIMITED', 'O&G Producer', '990010135', 'VITOL GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Harshvardhan V', '1493184', 'Is it possible to engage with the client to understand if there are project level emission data (Scope1/2/3) available? When do they plan to track this. Please elucidate on the policy related transition risk faced by the project - Is there any committment applicable for power plants in Ghana -- Although Q4.2 mentions no impact in next 5-10 years, its not very clear if polciy im[act from 2025 onwards will not have any impact on the asset being funded', NULL, NULL, NULL, 'NETHERLANDS (KINGDOM OF THE)', 'Existing to Bank', NULL, 'Renjith  Scariah', '1540001', 'NL', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-13 07:22:36', '2024-03-19 11:08:22'),
  (21454, '13610740', 'TATA STEEL EUROPE LIMITED', 'Metal & Mining Producers', '990059091', 'TATA GROUP INDIA', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'To comment on TSE''s exposure to carbon pricing through its participation in the EU/UK ETS', NULL, NULL, NULL, 'INDIA', 'Existing to Bank', NULL, 'Renjith  Scariah', '1540001', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2023-12-13 08:17:34', '2024-05-03 10:34:04'),
  (21493, '14020656', 'CB_23090304', 'Food, Beverage & Tobacco', NULL, NULL, 'Make in Progress', NULL, NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'To provide an update on the envisaged EPC ratings that will be assigned to the properties under development', NULL, 'Liu, Shuk Fan', '1551380', 'AUSTRALIA', 'Existing to Bank', NULL, 'null null', '1666829', 'AU', 'CRQ v4', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-09 13:53:28', '2025-09-09 13:55:11'),
  (21498, '11213970', 'AEY FRAF YR', 'Metal & Mining Producers', NULL, NULL, 'Make in Progress', NULL, NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'To check with the client if they would look to certify the building (Green Building Label) once constructed.', NULL, NULL, NULL, 'SWITZERLAND', 'Existing to Bank', NULL, 'null null', '1666829', 'GB', 'CRQ v4', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-09 15:39:56', '2025-09-09 15:40:10'),
  (21586, '11244256', 'LNAME11244256', 'T & S - Aviation', '990058214', 'TURKISH AIRLINES', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Would recommend a route analysis to understand the typical areas that Turkish Airlines is flying and what the frequency of the routes are. We can then assess which locations the planes are typically in and perform a weighted review of the physical hazards. Additionally, it could also help understand a weighted view of transition policies that might be in place and this information can be included in the BCA.1 Hub location was deemed as having extreme future precipitation risk - recommend analysis on potential impacts to this one Hub and if it has a detrimental impact on overall operations. Climate Analyst Team to provide Hub scoring.Finally, client outreach is recommended to understand if changing weather conditions in regions has seen any effect on passenger demand to those destinations.', NULL, NULL, NULL, 'TURKIYE', 'Existing to Bank', NULL, 'null null', '1618369', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-14 14:54:20', '2024-02-28 12:44:07'),
  (21595, '13924204', 'United Chattogram Power Ltd', 'Utilities', '990050685', 'UNITED GROUP.', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Antonio Rendina', '1599218', 'To comment in the BCA P2 on the Power Plant''s emission intensity compared to that of traditional OCGT power plants', NULL, NULL, NULL, 'BANGLADESH', 'Existing to Bank', NULL, 'Ewa Baran', '1663704', 'BD', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-15 09:49:29', '2024-02-19 11:52:30'),
  (21601, '11118619', 'AL FUTTAIM TRADING (L.L.C)', 'Automobiles & Components', '990021024', 'ABDULLA AL FUTTAIM GROUP', 'Cancelled', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'In the BCA P2, to propose an analysis over the Client''s supplier and ascertain the vehicles traded based on their powertrain', NULL, NULL, NULL, 'UNITED ARAB EMIRATES', 'Existing to Bank', NULL, 'Elzbieta Brodzicka', '2007983', 'AE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-15 11:18:12', '2024-02-22 14:38:43'),
  (21602, '13687864', 'AL TASNIM ENTERPRISES LLC', 'Building Products, Construction & Engineering', '990063783', 'AL TASNEEM GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'According to previous CRA: "RM Outreach performed. Client in exit process: On 19th if January Dimuthu Udugampola wrote: "SCB Oman has exited CB, Al Tasnim is a CB name due to our commitment on the project specific limit exit is delayed. In the project that we supported Al Tasnim was the sub-contractor, however due to a dispute main contractor had with MOH (Ministry of Health), the main contractor was terminated by MOH and Al Tasnim was appointed as the main contractor however due to various issues MOF (Ministry of finance), Oman is yet to ratify the contract signed by MOH and Al Tasnim. In view of this long delays in ratification and delay in receivables, we have requested client to exit and in Jan 2023, I have send an email recalling SCB limits. Considering current relationship challenges its not correct to engage with client for climate risk questions. "', NULL, NULL, NULL, 'OMAN', 'Existing to Bank', NULL, 'Dorota Ptasinska', '1611650', 'OM', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-15 11:19:35', '2024-01-07 13:23:26'),
  (21619, '13950748', 'Nawwar Renewable Energy Company', 'Utilities', '990326592', 'ACWA Power', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Antonio Rendina', '1599218', 'According to the CCRA report, "solar panel efficiency is reduced during high heats by 0.3% to 0.5% for every degree above 25 ºC (Ecoflow, 2023)" - Credit Analyst is request to make a qualitative assessment of the financial implication of heatwave events on the projects'' profitability', NULL, NULL, NULL, 'SAUDI ARABIA', 'Existing to Bank', NULL, 'Ewa Baran', '1663704', 'SA', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2023-12-15 11:48:45', '2024-04-03 13:53:05'),
  (21665, '13807527', 'Siemens Energy Co.,Ltd.', 'Other Capital Goods', '990356638', 'Siemens Energy Group', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Antonio Rendina', '1599218', 'To assess the % of revenues linked to renewable projects in China as a % of total revenues at risk from the transition to a low carbon economy', NULL, NULL, NULL, 'GERMANY', 'Existing to Bank', NULL, 'Devika Rose Roy', '2001769', 'DE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-15 16:31:31', '2024-02-01 01:27:28'),
  (21700, '11359700', 'LNAME11359700', 'Metal & Mining Producers', '990072166', 'Yunnan Investment Group', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', 'Recommended to perform client outreach to understand any climate transition plans or technologies to be employed, given the high carbon nature of the business sector. Call report to be shared with cliamte analyst team', NULL, NULL, NULL, 'CHINA', 'Existing to Bank', NULL, 'Taigh Olatomiwa Adebajo', '1665883', 'CN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-15 17:34:30', '2024-02-07 02:22:27'),
  (21709, '11121550', 'SHARJAH CEMENT & INDUSTRIAL DEVELOPMENT .CO', 'Building Products, Construction & Engineering', '990019351', 'SHARJAH CEMENT AND INDUSTRIAL DEVELOPMENT COMPANY PSC', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Suggested analysis to understand the current client clinker ratio and whether there is scope to reduce this ratio with the supply of alternative materials to reduce emissions intensity of cement production operations.', NULL, 'Rouse, Elliott', '1489063', 'UNITED ARAB EMIRATES', 'Existing to Bank', NULL, 'Taigh Olatomiwa Adebajo', '1665883', 'AE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729209600', NULL, NULL, '2023-12-15 17:40:21', '2024-08-29 07:13:21'),
  (21710, NULL, NULL, NULL, NULL, NULL, 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Enis Hasimi', '2009422', 'To gather more information on applicable short-term/medium term sovereign policies, local and/or international regulations impacting the sector/client.', NULL, NULL, NULL, NULL, 'Existing to Bank', NULL, 'Taigh Olatomiwa Adebajo', '1665883', NULL, 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-15 17:41:03', '2024-03-26 10:47:09'),
  (21719, '11228556', 'CNPC FINANCE (HK) LIMITED', 'O&G Producer', '990027478', 'CHINA NATIONAL PETROLEUM CORPORATION (CNPC)', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Shuk Fan Liu', '1551380', 'Due to an ESG Nav issue, this client should be rated Amber, due to a default in the short-term NZ scenario PD modelling. Please follow the required RT.', NULL, NULL, NULL, 'CHINA', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'CN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-17 17:37:03', '2024-02-19 10:02:19'),
  (21735, '13721682', 'Petronas International Corporation Ltd', 'O&G Producer', '990011600', 'PETRONAS GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Harshvardhan V', '1493184', 'CA to analyse progress towards stated targets. Company mentions reduction of emissions by 25% as of 2030 based on a baseline (mentioned in CDP) but current progress is only 3-4%. How does the company plan to acheive its target? is there associated capex planned to help acheive this -- please check with the client and include these figures in your assessment', NULL, NULL, NULL, 'MALAYSIA', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'MY', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-17 18:03:31', '2024-02-28 06:17:02'),
  (21750, '11272444', 'SK SILTRON CO LTD', 'Technology Hardware & Equipment', '990000413', 'SK GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'SK Siltron has set the company-wide net-zero target for Scope 1 and 2 emissions, and disclosed mid-term targets for setting corporate net-zero targets, aiming for a 55% reduction by 2030 and 100% reduction by 2040. Emissions have reduced by 9.7% since the base year.Sk Siltron intends to conduct various activities for category 9 and 10 to induce greenhouse gas reduction in order to achieve Scope 3 greenhouse gas goals. SK Siltron will work with customers to reduce greenhouse gases. Customers will proceed with greenhouse gas reduction and Sk Siltron will be encouraged to move according to Net Zero target setting and 1.5℃ scenario. Scope 3 emissions target: 20% reduction by 2050 from 2020 base year, achieving 23.98% of the target.', NULL, NULL, NULL, 'KOREA, REPUBLIC OF', 'Existing to Bank', NULL, 'Peter Jared Delaney', '1665885', NULL, 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-18 08:19:09', '2024-01-29 01:22:52'),
  (21768, '13955351', 'Populus Realty Limited', 'CRE', '990010970', 'BHARTI GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'The NTB template is a shortened one in order to balance volumes and an attempt to finishing a CRA pre onboarding, hence the analysis here is limited. Please supplement asset level data in the BCA. Is the building certified/planned to be certified by  IGBC/LEED etc ? What are the expected emissions from the operations of the building -- esp. given India is heavily dependant on coal for power generation at the moment. Also apart from the grid, which is slightly outside control, are there any energy efficiency measures at building level  (eg: heating systems/captive power etc) that are planned.', NULL, NULL, NULL, 'INDIA', 'New to Bank', NULL, 'Renjith  Scariah', '1540001', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-19 04:51:23', '2024-01-02 08:10:02'),
  (21771, '13946879', 'ALBIHOUTH WASTE TO ENERGY PROJECT COMPANY - L.L.C', 'Utilities', '990024456', 'UNITED ARAB EMIRATES GOVERNMENT', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'New', 'Antonio Rendina', '1599218', 'The project''s emission intensity depends on the type of waste being employed. Higher % of non-recyclable waste vs recyclable is likely to lead to higher emission intensity.  In BCA P2, AA is suggested to provide an estimate in the BCA P2 regarding the % of recyclable waste vs non-recyclable waste being used in the power plant - if no information is available, then to provide this at country level.', NULL, 'Liu, Shuk Fan', '1551380', 'UNITED ARAB EMIRATES', 'Existing to Bank', NULL, 'Ewa Baran', '1663704', 'AE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2023-12-19 08:55:32', '2024-02-26 15:48:08'),
  (21793, '11314697', 'BAHRAIN STEEL BSCC E.C.', 'Metal & Mining Producers', '990020762', 'GULF INVESTMENT CORPORATION GSC GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Identify vessels owned by BS and understand the impact of IMO regulations, to see if additional costs are required to retrofit / upgrade vessels or planned costs will arise to meet Net Zero commitments. Identify how the added capex may affect company profitability in the futureCan we interact with the client to understand if they have any systems / defences in place to prevent future sea level rise impacting the operations of the port and or pelletising plants, or if they are planning to introduce any such features. If so – what might be the capex associated with implementing such defences. Additionally, could we ask if they have any insurance policies in place to cover them for damage to assets as well as revenue disruptions insurance, from any climate related weather events / sea level rises.', NULL, NULL, NULL, 'KUWAIT', 'Existing to Bank', NULL, 'Yvonne  Jen', '1600990', 'KW', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-21 12:39:54', '2024-02-26 08:21:18'),
  (21832, '11162155', 'LNAME11162155', 'Other Materials', '990001322', 'HENKEL GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'To follow up on Q 4.1.1 : how is the client progress on deviating from production/revenue mix high-carbon products (Coal, Oil, Fossil Fuels) and finding new sustainable alternative ways?', NULL, NULL, NULL, 'GERMANY', 'Existing to Bank', NULL, 'Dalma Beatrix  Komjati', '1665875', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2023-12-29 12:57:42', '2024-02-14 08:32:36'),
  (21862, '11020961', 'MINMETALS CHEERGLORY LIMITED', 'Commodity Traders', '990003087', 'MINMETALS', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Chirag Jain', '1575987', 'RM team is requested to elaborate on the plans / actions taken by the group to reduce GHG emissions from its Metal division, Quantitative targets of the group to reduce emissions and progress achieved in the upcoming renewal BCA', NULL, NULL, NULL, 'HONG KONG', 'Existing to Bank', NULL, 'null null', '2006082', 'HK', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2024-01-03 09:13:46', '2024-02-27 03:43:28'),
  (21902, '11285604', 'DANGOTE CEMENT PLC', 'Building Products, Construction & Engineering', '990047253', 'DANGOTE GROUP', 'Rejected to Maker', 'Red', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'In the BCA P2, to (i) comment on  carbon pricing risks faced by DCP and its financial impact, (ii) highlight refinancing risks driven by investors'' climate change awareness, (iii) earmark financial impact from physical risks. Email will be shared by Climate Advisor team on how to address these topics', NULL, NULL, NULL, 'NIGERIA', 'Existing to Bank', NULL, 'Taigh Olatomiwa Adebajo', '1665883', 'NG', 'CRQ v3', NULL, NULL, NULL, NULL, '1730044800', NULL, NULL, '2024-01-15 12:03:20', '2024-08-29 10:15:31'),
  (21931, '13873135', 'ZHEJIANG SEAPORT FINANCIAL LEASING CO LTD', 'Financial Institutions', '990358971', 'ZHEJIANG SEAPORT GROUP ', 'Ready for Review', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'COmment on whether the entity/when the entity would monitor the emission intensity of its portfolio of ships. Ships which are misaligned to Poseidon;s framework, or very old/energy inefficient or not aligned to IMO may have a risk of finding longer term leasing contracts. Who would bear the costs/risk in this situation ?', NULL, 'V, Harshvardhan', '1493184', 'CHINA', 'Existing to Bank', NULL, 'Devika Rose Roy', '2001769', 'CN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2024-01-17 16:32:25', '2024-10-16 17:57:37'),
  (21943, '13961888', 'Raizen Trading SA', 'Automobiles & Components', NULL, NULL, 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'Shuk Fan Liu', '1551380', 'CA to discuss the types of biofuel generation (i.e. % Breakdown of First-generation biofuels or conventional biofuels and Second-generation biofuels or advanced biofuels) the Client/Group is producing.', NULL, NULL, NULL, 'SWITZERLAND', 'New to Bank', NULL, 'Renjith  Scariah', '1540001', 'US', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2024-01-17 20:56:27', '2024-02-20 14:46:41'),
  (21990, '11154598', 'FORD MOTOR COMPANY', 'Automobiles & Components', '990047725', 'FORD MOTOR GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'To comment on the company''s ability to meet its own emission reduction targets and execute its transition investment plans', NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Elzbieta Brodzicka', '2007983', 'US', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2024-01-19 09:03:10', '2024-04-05 14:13:41'),
  (21992, '11438516', 'PT INDIKA ENERGY TBK', 'Coal Producers', '990077551', 'INDIKA GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Chirag Jain', '1575987', 'RM team to include analysis on a) financial impact of Indonesia ETS on revenue from Cirebon power plant  b) Impact of decline in coal revenues (Based on Coal revenue dependency target) on the profitability margins of the company in BCA part -II', NULL, NULL, NULL, 'INDONESIA', 'Existing to Bank', NULL, 'Elzbieta Brodzicka', '2007983', 'ID', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2024-01-19 09:11:33', '2024-04-01 02:25:17'),
  (22110, '11044360', 'SOCIETE IVOIRIENNE DE RAFFINAGE', 'O&G Refiners and Petrochemicals', '990344304', 'COTE D''IVOIRE GOVERNMENT', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Physical risk trigger is not required as location of the refinery is available, however given that 32.5% of the exports are to two countries Mali and Murkina Faso, analyst is expected to comment on climate risk faced by the counterparty in the two countries (is it concentrated to a few buyers?)/ alternatively please seek out climate risk ranking for the two countries from country risk/climate risk team and to be included in the BCA', NULL, 'Liu, Shuk Fan', '1551380', 'COTE D''IVOIRE', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'CI', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2024-01-19 15:41:23', '2024-02-27 01:20:33'),
  (22180, '11243924', 'L NAME 11243924', 'Building Products, Construction & Engineering', '990033690', 'SHUN SHING GROUP', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'From Elliott: "To analyse the make-up of the product sales (e.g. acquire a breakdown of product by sales) from CEMCOA."', NULL, 'Jain, Chirag', '1575987', 'HONG KONG', 'Existing to Bank', NULL, 'Monalisa Banerjee', '1563645', 'HK', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-01-22 12:56:57', '2024-03-25 13:53:45'),
  (22343, '11327342', 'VIETNAM ELECTRICITY', 'Utilities', '990047503', 'ELECTRICITY OF VIETNAM', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'Antonio Rendina', '1599218', NULL, NULL, 'Rendina, Antonio', '1599218', 'VIETNAM', 'Existing to Bank', NULL, 'Yvonne  Jen', '1600990', 'VN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729958400', NULL, NULL, '2024-01-22 17:29:42', '2024-04-15 15:34:59'),
  (22461, '11125227', 'LNAME11125227', 'Metal & Mining Producers', '990012573', 'SAFAL INVESTMENTS (MAURITIUS) LTD', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'There is a lack of climate driven policy in Tanzania and hence likelihood of carbon tax impacts is also low at this current stage. Would suggest monitoring of horizon for carbon tax or ETS schemes and recommend ESG A engagement.Monitoring should be in place due to upcoming policy implications and so entity could move to Red is policy pressure increases in the near future.', NULL, NULL, NULL, 'TANZANIA, UNITED REPUBLIC OF', 'Existing to Bank', NULL, 'Taigh Olatomiwa Adebajo', '1665883', 'TZ', 'CRQ v3', NULL, NULL, NULL, NULL, '1730044800', NULL, NULL, '2024-01-23 08:16:47', '2024-06-28 15:37:54'),
  (22523, '13796101', 'BW EPIC KOSAN VESSELS ONE PTE. LTD.', 'O&G Tanker - Water Transport', '990196252', 'BW GROUP LIMITED', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Request the BCA to comment on the ESG KPI''s that are part of the loan, what is the progress made on these.', NULL, NULL, NULL, 'SINGAPORE', 'Existing to Bank', NULL, 'Peter Jared Delaney', '1665885', 'SG', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2024-01-23 10:59:27', '2024-05-07 10:18:08'),
  (22669, '11075386', 'MALAYSIA SMELTING CORPORATION BERHAD', 'Metal & Mining Producers', '990057861', 'TECITY GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'Elliott Rouse', '1489063', 'Entity assets are quite exposed to precipitation stress - recommend reaching out to understand physical adaption plans given the potential flood and rain hazards that could damage smelting equipment.', NULL, NULL, NULL, 'MALAYSIA', 'Existing to Bank', NULL, 'Ranim Tarakji', '2003718', 'MY', 'CRQ v3', NULL, NULL, NULL, NULL, '1730044800', NULL, NULL, '2024-01-23 15:09:27', '2024-05-24 06:36:56'),
  (22769, '11040704', 'FORMOSA PETROCHEMICAL CORPORATION', 'O&G Refiners and Petrochemicals', '990002163', 'FORMOSA PLASTICS GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Harshvardhan V', '1493184', 'BCA to analyse emission intensity of clent''s operations to understand the actual trend. (Trend of Scope1 emissions/unit of production or revenue -- simlar for Scope 2 and Scope3 to understand the trend clearly which seems to be up and down)', NULL, NULL, NULL, 'TAIWAN', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'TW', 'CRQ v3', NULL, NULL, NULL, NULL, '1729958400', NULL, NULL, '2024-01-23 18:16:12', '2024-04-23 07:00:13'),
  (22781, '11323439', 'SHELL PLC', 'O&G Producer', '990010539', 'ROYAL DUTCH / SHELL GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Harshvardhan V', '1493184', 'Subjective/Financial analysis to assess materiality of climate risk  --> refer email sent by climate advisor on this topicAlso include peer comparison while covering this topic in the BCA -- Shell currently lags behind majors in target stting', NULL, NULL, NULL, 'NETHERLANDS (KINGDOM OF THE)', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-01-23 18:25:33', '2024-03-20 11:06:35'),
  (22811, '13630679', 'FRASERS PROPERTY HOLDINGS (THAILAND) CO., LTD.', 'CRE', '990044736', 'T.C.C.GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Company has set a target to have 80% of all their owned and managed assets by 2024 being certified as green -- Please comment on this in the BCA, is the company exepcted to acheive this target by year end (please monitor). Also what is the restrition for the remaining 20% ?Is there a timelie for them as well', NULL, NULL, NULL, 'THAILAND', 'Existing to Bank', NULL, 'Monalisa Banerjee', '1563645', 'TH', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2024-01-23 20:31:42', '2024-05-08 03:16:18'),
  (22834, '11085720', 'PT KRAMA YUDHA TIGA BERLIAN MOTORS', 'Automobiles & Components', '990063403', 'MITSUBISHI CORPORATION GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'To confirm if the transition risk and company''s emissions are being reported at Mitsubishi Corp level. Also, to confirm if Daimler Truck AG (which is the majority shareholder - 89.29% of Mitsubishi Fuso Truck & Bus Corporation) should be used for Climate Risk assessment, given that the entity (PT Krama Yudha Tiga Berlian Motors) distributes exclusively Mitsubishi Fuso-branded commercial vehicles and parts.', NULL, NULL, NULL, 'INDONESIA', 'Existing to Bank', NULL, 'Ewa Baran', '1663704', 'ID', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-01-24 07:22:01', '2024-03-27 02:55:35'),
  (22858, '13131729', 'EXPEDIA, INC.', 'Consumer Services', '990188251', 'EXPEDIA GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Recommend outreach to client to understand if they have data / statistics on which airlines they broker for and their climate management policies, particularly from physical risk. Additionally if Expedia has insurance against potential cancellations / delays for aircraft affected by climate hazards to understand how they are hedged against climate risks.', NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Sneha Chourasia', '2001416', 'US', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2024-01-24 08:50:58', '2024-06-04 05:21:23'),
  (22911, '11269352', 'DAESANG CORPORATION', 'Food, Beverage & Tobacco', '990043082', 'DAESANG CORP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'In the BCA P2, to highlight financial risks linked to the Korea ETS and report on both the emission rights freely allocated and emission levels', NULL, NULL, NULL, 'KOREA, REPUBLIC OF', 'Existing to Bank', NULL, 'Devika Rose Roy', '2001769', NULL, 'CRQ v3', NULL, NULL, NULL, NULL, '1730044800', NULL, NULL, '2024-01-24 14:29:37', '2024-06-09 23:59:54'),
  (22972, '11326455', 'PERUSAHAAN PERSEROAN (PERSERO) PT PERUSAHAAN LISTRIK NEGARA', 'Utilities', '990024451', 'INDONESIA GOVERNMENT', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Antonio Rendina', '1599218', 'Business team is requested to add into the client’s financial projections both (i) the physical risk costs as indicated in the latest approved Climate Risk Assessment, and (ii) an estimation of the transition risk costs associated with the carbon pricing mechanism.', NULL, NULL, NULL, 'INDONESIA', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'ID', 'CRQ v3', NULL, NULL, NULL, NULL, '1729958400', NULL, NULL, '2024-01-29 05:59:27', '2024-06-21 09:44:10'),
  (22983, '13983097', 'MidOcean Energy Holdings Pty Ltd', 'O&G Producer', NULL, NULL, 'Approved', 'Red', NULL, NULL, NULL, NULL, 'New', 'Antonio Rendina', '1599218', 'To comment on the risks faced under the Safeguard Mechanism and highlight the transmission channels', NULL, 'Jain, Chirag', '1575987', 'AUSTRALIA', 'New to Bank', NULL, 'Abhisek  Joardar', '1668812', 'AU', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-01-30 02:10:34', '2024-02-13 16:53:33'),
  (23008, '11077430', 'CHEVRON MALAYSIA LIMITED', 'Commodity Traders', '990000249', 'CHEVRON CORPORATION', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', 'Recommend conducting an analysis on where the products sol by Chevron Malaysia are produced and if there are climate policies / potential carbon costs associated with the production region and if this could increase the COGS of the products and affect demand for Chevron MY', NULL, NULL, NULL, 'MALAYSIA', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'MY', 'CRQ v3', NULL, NULL, NULL, NULL, '1730044800', NULL, NULL, '2024-02-01 17:26:58', '2024-04-29 09:31:31'),
  (23031, '13788678', 'HISTYLE RETAIL PRIVATE LIMITED', 'CRE', '990045986', 'RUNWAL GROUP', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Is there a plan to have the building certified once building is constructed ? please share comments in the BCA on wheher there is any risk to valuation because there are no details of whether the asset is energy efficeint or not -- LEED/Indian Green building council certifications are becoming more common in the market.', NULL, 'Liu, Shuk Fan', '1551380', 'INDIA', 'Existing to Bank', NULL, 'null null', '1666829', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-02-02 11:51:53', '2024-03-19 17:04:35'),
  (23038, '13904481', 'RENEW SOLAR POWER PRIVATE LIMITED', 'Utilities', NULL, NULL, 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'To comment on (i) risks brought by a reduction in solar photovoltaic modules due to higher solar irradiation, (ii) risks faced as a result of sales of carbon certificates business', NULL, NULL, NULL, 'INDIA', 'New to Bank', NULL, 'Renjith  Scariah', '1540001', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2024-02-06 12:06:52', '2024-02-22 06:08:11'),
  (23047, '13984189', 'GOLDEN AQUAMARINE INC.', 'T & S - Bulker Water Transport', NULL, NULL, 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'Harshvardhan V', '1493184', 'Please assess impact of EU ETS on the 6 vessels being financed => what % of voyages are expected to be connected to EU ports. (this information might be avilable for the vessles for last year if the are operational vessels)', NULL, NULL, NULL, 'NORWAY', 'New to Bank', NULL, 'Peter Jared Delaney', '1665885', 'SG', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-02-09 09:38:35', '2024-02-15 01:41:49'),
  (23070, '13985286', 'Vivacious Aircraft Leasing Limited', 'T & S - Aviation', NULL, NULL, 'Approved', 'Red', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'RT to perform client outreach to understand full disclosures package from the client with regards to aviation portion of TATA business, as NTB approach limits full CTP score', NULL, 'Rouse, Elliott', '1489063', 'IRELAND', 'New to Bank', NULL, 'Abhisek  Joardar', '1668812', 'SG', 'CRQ v3', NULL, NULL, NULL, NULL, '1729958400', NULL, NULL, '2024-02-16 08:12:08', '2024-05-28 14:44:30');
INSERT INTO mstr.risk_trigger_report VALUES
  (23082, '13665751', 'CHRYSAOR E&P FINANCE LIMITED', 'O&G Producer', '990321791', 'CHRYSAOR HOLDINGS LIMITED', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', 'Further information/client engagement sought on the below after deal completion:1. Post deal completion, comment on emission statistics of the combined entity as well as Scope1,2,3 emission and routine flaring interim and long term targets. Both individual groups have only Scope1,2, targets whereas for the exploration O&G sector, Scope 3 downstream are most material  -- Coverage of these emissions under existing carbon policies to be assessed financially (including UK ETS)2. There is limited to no physical risk assessment done for assets acquired from Wintershall based on Wintershalll''s existing ESG repoerts, please provide an assessment on these before the renewal BCA3. Client''s long term strategy to reduce GHG emission intensity of its operations -- given limited diversification in the nature of business and the nature of sector', NULL, 'Mundra, Piyush', '1191828', 'UNITED KINGDOM', 'Existing to Bank', NULL, 'Dagmara Popielarczyk', '1663712', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-02-20 14:10:55', '2024-02-23 09:34:38'),
  (23084, '13982834', 'DUNCHON HYUNDAI 1ST APARTMENT REMODELING CONSORTIUM', 'CRE', '990377382', 'DUNCHON HYUNDAI 1ST APARTMENT REMODELING CONSORTIUM', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Although there is completion guarantee from POSCO,  BCA to assess how physical riks from climate are mitigted in the absence of an insurance both during construction and also after construction  -> Eg: Iif it impacts the pre=-sale plan, and thereby haas an impact on cashflow generated for repayment of our facilty. Please note historical evidence of completion is a good mitigant but climate risk is forwqard looking, (its not a risk which was material in the past)', NULL, NULL, NULL, 'KOREA, REPUBLIC OF', 'New to Bank', NULL, 'null null', '1666829', 'KR', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2024-02-21 04:33:50', '2024-04-04 07:33:40'),
  (23085, '13984677', 'Shine Luna Co., Ltd.', 'Utilities', NULL, NULL, 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Given the location of the project is at extreme risk for flooding and storms as per Munich Re assessment , RM team is requested to highlight physical risk adaptation plans of the entity to mitigate these risks.', NULL, NULL, NULL, 'TAIWAN', 'New to Bank', NULL, 'Devika Rose Roy', '2001769', 'TW', 'CRQ v3', NULL, NULL, NULL, NULL, '1729440000', NULL, NULL, '2024-02-21 06:18:44', '2024-03-12 03:31:56'),
  (23113, '13981543', 'SHELL PETROLEUM COMPANY LIMITED(THE)', 'O&G Producer', NULL, NULL, 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Refer analysis on Shell plc -- Since this is a central treaury vehicle , its directly connected to the Group', NULL, NULL, NULL, 'UNITED KINGDOM', 'New to Bank', NULL, 'Yvonne  Jen', '1600990', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1729468800', NULL, NULL, '2024-03-05 15:32:01', '2024-03-20 11:07:08'),
  (23506, '13988775', 'Mercedes-Benz Kamyon Finansman A.S.', 'Automobiles & Components', NULL, NULL, 'Approved', 'Green', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'To highlight the second order financial risks faced by Mercedes-Benz Kamyon Finansman A.S. from physical risk amid its consumer financing role within the Group', NULL, NULL, NULL, 'TURKIYE', 'New to Bank', NULL, 'Elzbieta Brodzicka', '2007983', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2024-04-08 07:50:09', '2024-04-16 08:48:41'),
