  (23555, '13789789', 'Kapstone Constructions Private Limited', 'CRE', '990238834', 'RUSTOMJEE GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'BCa to comment on how client plans to manage physical risk, and whether the extensions in the property which are being constructed are also certified Gold by IBC', NULL, NULL, NULL, 'INDIA', 'Existing to Bank', NULL, 'Aljaz Leva', '1664889', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2024-04-21 18:55:21', '2024-06-12 09:28:49'),
  (23825, '11062853', 'LNAME11062853', 'Household & Personal Products', '990000494', 'UNILEVER GROUP', 'Review by RM', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, NULL, NULL, NULL, NULL, 'UNITED KINGDOM', 'Existing to Bank', NULL, 'Aleksandra  Ziemlinska', '2018956', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1729209600', NULL, NULL, '2024-04-24 11:11:21', '2024-08-30 11:50:40'),
