  (23988, '13715379', 'LNAME13715379', 'Utilities', '990053591', 'KEPCO', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'In the BCA P2, to discuss the generation efficiency levels of the plant under different scenarios and link the P90 weather considerations to potential downside risks from climate change', NULL, NULL, NULL, 'JORDAN', 'Existing to Bank', NULL, 'Ewa Baran', '1663704', 'JO', 'CRQ v3', NULL, NULL, NULL, NULL, '1729036800', NULL, NULL, '2024-04-25 19:15:54', '2024-08-05 06:02:51'),
  (24151, '13686001', 'LNAME13686001', 'T & S - Aviation', '990011789', 'AIR FRANCE - KLM GROUP', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'Elliott Rouse', '1489063', 'I addition to the financial projections being developed - would ask to check the starting FCF and EBITDA balances to understand if these are in line with historic averages, or they are still muted from impact of Covid. The weak financial starting position is a key driver of the Red rating.', NULL, 'Rouse, Elliott', '1489063', 'JAPAN', 'Existing to Bank', NULL, 'Shubham Harsh', '2008896', 'JP', 'CRQ v3', NULL, NULL, NULL, NULL, '1729036800', NULL, NULL, '2024-04-27 12:09:08', '2024-07-17 09:27:20'),
  (24181, '11206569', 'QATAR ALUMINIUM LIMITED', 'Metal & Mining Producers', '990060274', 'GOVERNMENT OF QATAR GROUP', 'Rejected to Maker', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Recommend engaging with client to understand the % energy mix used for aluminium smelting, to get a better understanding on the emissions generation and reliance on high carbon products.', NULL, NULL, NULL, 'QATAR', 'Existing to Bank', NULL, 'Shubham Harsh', '2008896', 'QA', 'CRQ v3', NULL, NULL, NULL, NULL, '1729036800', NULL, NULL, '2024-04-27 12:25:54', '2024-09-05 02:41:58'),
  (24201, '11018555', 'KUEHNE & NAGEL LIMITED', 'Transportation and Storage', '990002233', 'KUEHNE + NAGEL GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, NULL, NULL, NULL, NULL, 'SWITZERLAND', 'Existing to Bank', NULL, 'Shreyash Sunil Dahale', '2020154', 'CH', 'CRQ v3', NULL, NULL, NULL, NULL, '1729008000', NULL, NULL, '2024-04-28 07:46:34', '2024-08-27 09:20:03'),
  (24207, '11164837', 'LNAME11164837', 'Transportation and Storage', '990030751', 'FEDEX CORP', 'Review by RM', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, NULL, NULL, NULL, NULL, 'UNITED STATES OF AMERICA', 'Existing to Bank', NULL, 'Shreyash Sunil Dahale', '2020154', 'US', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2024-04-28 08:43:40', '2024-08-30 06:28:01'),
  (24224, '11018713', 'CROWN WORLDWIDE (HK) LIMITED', 'Transportation and Storage', '990002424', 'CROWN WORLDWIDE', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'The company does not disclose a group-level target for reducing its emissions but plans to set a net-zero target in Q4 2024. Thus, we are unable to comment on progress against the alignment plan.', NULL, NULL, NULL, 'HONG KONG', 'Existing to Bank', NULL, 'Monalisa Banerjee', '1563645', 'HK', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2024-04-28 09:53:19', '2024-08-14 02:59:46'),
  (24343, '11317224', 'LNAME11317224', 'T & S - Aviation', '990095491', 'AIR ARABIA', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'As part of the additional analysis, the company has not disclosed quantitative targets relevant to emission reductions. Hence, we are unable to comment on progress against the alignment plan.', NULL, NULL, NULL, 'UNITED ARAB EMIRATES', 'Existing to Bank', NULL, 'Shreyash Sunil Dahale', '2020154', 'AE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729180800', NULL, NULL, '2024-04-29 12:54:43', '2024-08-23 08:18:56'),
  (24354, '13965421', 'RADIANCE MH SOLAR PARK PRIVATE LIMITED', 'Utilities', '990375723', 'RADIANCE RENEWABLES PRIVATE LIMITED', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'In the BCA P2, to evaluate the financial implications of extreme heat levels on the plant''s locations and discuss how its efficiency levels could be impaired during heatwave events', NULL, NULL, NULL, 'INDIA', 'Existing to Bank', NULL, 'Kamila Waclawska', '1632774', 'IN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729209600', NULL, NULL, '2024-04-29 13:16:28', '2024-08-05 06:44:52'),
  (24460, '13803679', 'SHENZHEN CHUANGWEI-RGB ELECTRONICS CO.,LTD', 'Technology Hardware & Equipment', '990046131', 'SKYWORTH', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'We cannot measure progress against the target, as the company has only disclosed its support for China’s 2060 carbon-neutrality goal.', NULL, NULL, NULL, 'CHINA', 'Existing to Bank', NULL, 'Shreyash Sunil Dahale', '2020154', 'CN', 'CRQ v3', NULL, NULL, NULL, NULL, '1729209600', NULL, NULL, '2024-04-29 14:58:30', '2024-08-19 08:58:06'),
  (24547, '13884696', 'RELIANCE INTERNATIONAL LIMITED', 'Commodity Traders', '990034049', 'MUKESH AMBANI GROUP', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', NULL, NULL, 'The company has announced a net-zero target for 2035 (with a 2020 base year) covering Scope 1 & 2 emissions. Based on the disclosed data in the annual report, it has been making steady progress towards this goal, achieving 7.58% of its targeted reduction as of the reporting year (FY2022-23).', NULL, NULL, NULL, 'UNITED ARAB EMIRATES', 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', 'AE', 'CRQ v3', NULL, NULL, NULL, NULL, '1730073600', NULL, NULL, '2024-05-02 00:56:02', '2024-09-24 08:51:57'),
  (24562, '11092319', 'LNAME11092319', 'Coal Producers', '990003556', 'BANPU GROUP', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Comment on why 2025 Emissions Intensity target for the mining business is higher than recent years'' (2019-23) actual achievement. Refer page 57 of client''s 2023 Sustainability Report.', NULL, 'Sivasankar, Giridhar', '1410763', 'THAILAND', 'Existing to Bank', NULL, 'Devika Rose Roy', '2001769', 'TH', 'CRQ v3', NULL, NULL, NULL, NULL, '1729008000', NULL, NULL, '2024-05-02 02:01:28', '2024-08-08 10:23:49'),
  (24644, '13993971', 'Project Grand Bidco (UK) Limited', 'Utilities', NULL, NULL, 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'While refreshing CRA with full ISIC, please enage with the client to understand if they acknolwedge physical risk, and have insurance coverage on their key assets ( to cover for asset damage and business disruption)', NULL, NULL, NULL, 'UNITED KINGDOM', 'New to Bank', NULL, 'V Kavya Gowri', '2006519', 'GB', 'CRQ v3', NULL, NULL, NULL, NULL, '1730044800', NULL, NULL, '2024-05-14 14:04:52', '2024-05-20 08:46:31'),
  (24651, '13977616', 'REPSOL SA', 'O&G Producer', '990372981', 'REPSOL...', 'Approved', 'Red', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Recommendation for 3-6months time ot request an Ad-hoc ETB CRA to get a more accurate assessment of Repsol, given it is a large O&G client in our portfolio.', NULL, 'Rouse, Elliott', '1489063', 'SPAIN', 'New to Bank', NULL, 'Klaudia Muszynska', '2001097', 'DE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729958400', NULL, NULL, '2024-05-17 06:36:39', '2024-06-14 09:36:21'),
  (24726, NULL, NULL, NULL, NULL, NULL, 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'Recommend performing analysis of the emissions impact from traditional infrastructure business and understand what portion of the overall revenue portfolio this contributes to, to see if they are more or less exposure to climate carbon costs.', NULL, NULL, NULL, NULL, 'New to Bank', NULL, 'Renjith  Scariah', '1540001', NULL, 'CRQ v3', NULL, NULL, NULL, NULL, '1729008000', NULL, NULL, '2024-06-03 11:07:05', '2024-07-07 20:39:55'),
