  (24810, NULL, NULL, NULL, NULL, NULL, 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'New', 'null null', NULL, 'In the BCA P2, to evaluate the financial impact (either qualitatively or quantitatively) of the Indonesia carbon tax and transmission channels from higher heat levels impact the plant''s location (making reference to current efficiency levels of the plant)', NULL, NULL, NULL, NULL, 'Existing to Bank', NULL, 'Abhisek  Joardar', '1668812', NULL, 'CRQ v3', NULL, NULL, NULL, NULL, '1729180800', NULL, NULL, '2024-07-08 08:30:52', '2024-08-07 08:44:24'),
  (25429, '11207447', 'ABU DHABI NATIONAL OIL COMPANY (ADNOC)', 'O&G Producer', '990024456', 'UNITED ARAB EMIRATES GOVERNMENT', 'Approved', 'Amber', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, '- BCA to comment on the financing plans to undertake the transition as per the transition plan of the company -- Have the capex requirements been included in the projections?', NULL, NULL, NULL, 'UNITED ARAB EMIRATES', 'Existing to Bank', NULL, 'V Kavya Gowri', '2006519', 'AE', 'CRQ v3', NULL, NULL, NULL, NULL, '1729958400', NULL, NULL, '2024-08-07 16:02:10', '2024-10-16 11:14:12'),
  (25485, '11018609', 'CTMA HOLDINGS LIMITED', 'CRE', '990001725', 'CTMA', 'Advisor Review in Progress', 'Red', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Q. HK has high reltively high physical risk, when is the company going to assess the impact of physical risk on its business, and setup an adaptation plan ? Please engage with client for the CARTs (and for this). This needs to be included in the BCA', NULL, NULL, NULL, 'HONG KONG', 'Existing to Bank', NULL, 'Shubham Harsh', '2008896', 'HK', 'CRQ v3', NULL, NULL, NULL, NULL, '1730044800', NULL, NULL, '2024-08-08 08:04:52', '2024-10-23 11:41:46'),
  (25541, '13093729', 'SUMMIT ASIA PACIFIC PTE. LTD.', 'Commodity Traders', '990012817', 'SUMMIT GROUP', 'Approved', 'Green', NULL, NULL, NULL, NULL, 'Review', 'null null', NULL, 'Recommended to understand the portion of revenues generated from refining activities vs. non emission intensity ones, to establish overall reliance and risk.', NULL, NULL, NULL, 'SINGAPORE', 'Existing to Bank', NULL, 'Yvonne  Jen', '1600990', 'SG', 'CRQ v3', NULL, NULL, NULL, NULL, '1729987200', NULL, NULL, '2024-08-08 10:18:36', '2024-10-15 07:58:00'),
