-- ============================================================
-- Risk Trigger Report - Create table + insert all 295 records
-- Schema: mstr
-- ============================================================

DROP TABLE IF EXISTS mstr.risk_trigger_report CASCADE;

CREATE TABLE mstr.risk_trigger_report (
    case_id                          INTEGER,
    entity_id                        VARCHAR(50),
    entity_name                      VARCHAR(200),
    sector_name                      VARCHAR(100),
    group_id                         VARCHAR(20),
    client_group_name                VARCHAR(200),
    case_status                      VARCHAR(50),
    grading_status                   VARCHAR(20),
    physical_risk_brag               VARCHAR(20),
    isic_code                        VARCHAR(20),
    isic_description                 VARCHAR(200),
    transition_risk_brag             VARCHAR(20),
    assessment_type                  VARCHAR(20),
    advisor_name                     VARCHAR(100),
    advisor_psid                     VARCHAR(20),
    additional_analysis              TEXT,
    proposed_additional_analysis     TEXT,
    approver_name                    VARCHAR(100),
    approver_psid                    VARCHAR(20),
    country_of_domicile              VARCHAR(100),
    entity_classification             VARCHAR(50),
    frequency                        VARCHAR(50),
    maker_name                       VARCHAR(100),
    maker_psid                       VARCHAR(20),
    primary_booking_location_country  VARCHAR(10),
    crq_version                      VARCHAR(20),
    risk_trigger_category            VARCHAR(100),
    types_of_risk_trigger            VARCHAR(100),
    borrower_type                    VARCHAR(50),
    main_borrower_leid               VARCHAR(50),
    main_borrower_case_id            VARCHAR(50),
    summary                          TEXT,
    description                      TEXT,
    created_date                     TIMESTAMP,
    modified_date                    TIMESTAMP
);

